files.css:
.title { color: #7c3aed; }
.lead { font-size: 1.15rem; font-weight: 600; }
p { color: #475569; font-family: sans-serif; }

.box {
  width: 200px;
  padding: 20px;
  border: 4px solid #3b82f6;
  margin: 16px;
  background: #eff6ff;
  font-family: sans-serif;
}

body { margin: 0; font-family: system-ui, sans-serif; }
.site-header { background: #2563eb; color: #fff; padding: 1rem; }
.site-header h1 { margin: 0; font-size: 1.25rem; }
.site-main { padding: 1.25rem; max-width: 36rem; }
.site-main h2 { color: #1e293b; margin-top: 0; }
.site-footer { background: #f1f5f9; color: #64748b; padding: 0.75rem 1rem; font-size: 0.85rem; border-top: 1px solid #dbeafe; }
